## Loader Implementation

```python
from pathlib import Path
import yaml
import jsonschema
from temper_placer.core.loop import Loop, LoopType, LoopPriority, LoopEvent, LoopPin, LoopCollection

class LoopLoader:
    def __init__(self, schema_path: Path | None = None):
        self.schema = self._load_schema(schema_path)

    def _load_schema(self, path: Path | None) -> dict:
        if path is None:
            path = Path(__file__).parent.parent.parent / 'configs' / 'schemas' / 'loop.schema.json'
        with open(path) as f:
            return json.load(f)

    def load(self, path: Path) -> Loop:
        '''Load a single loop from YAML file'''
        with open(path) as f:
            data = yaml.safe_load(f)

        # Validate against schema
        jsonschema.validate(data, self.schema)

        return self._parse_loop(data)

    def load_directory(self, directory: Path) -> LoopCollection:
        '''Load all loop YAML files from a directory'''
        loops = []
        for path in directory.glob('*.yaml'):
            loops.append(self.load(path))
        return LoopCollection(loops=loops)

    def _parse_loop(self, data: dict) -> Loop:
        pins = [
            LoopPin(
                component_ref=p['component'],
                pin_name=str(p['pin']),
                net_name=p.get('net')
            )
            for p in data.get('pins', [])
        ]

        events_data = data.get('events', {})
        events = LoopEvent(
            di_dt=events_data.get('di_dt'),
            dv_dt=events_data.get('dv_dt'),
            frequency_hz=events_data.get('frequency_hz'),
            peak_current_a=events_data.get('peak_current_a'),
            rms_current_a=events_data.get('rms_current_a'),
            ringing_freq_hz=events_data.get('ringing_freq_hz'),
        )

        return Loop(
            name=data['name'],
            loop_type=LoopType(data['loop_type']),
            description=data['description'],
            pins=pins,
            components=data.get('components', []),
            nets=data.get('nets', []),
            max_area_mm2=data.get('max_area_mm2', 100.0),
            priority=LoopPriority(data.get('priority', 'medium')),
            events=events,
            return_layer=data.get('return_layer'),
            return_net=data.get('return_net'),
        )
